#include <Wire.h>
#include <MPU6050.h>
#define MTR_IN1 5
#define MTR_IN2 6
#define MTR_ENA 7
#define POT_PIN A0
#define BUZZER 8
#define LED 9
#define BUF_N 64
#define DT 0.02f
MPU6050 mpu;
float vbuf[BUF_N]={0};
int vidx=0;
float intg=0,lastE=0;
float lastPos=0;

float vibration_rms_window(float sample,float*buf,int*idx,int n){
  buf[(*idx)%n]=sample;(*idx)++;
  float s=0;for(int i=0;i<n;i++)s+=buf[i]*buf[i];
  return sqrt(s/n);
}

void drive_motor(int pwm){
  if(pwm>0){digitalWrite(MTR_IN1,HIGH);digitalWrite(MTR_IN2,LOW);analogWrite(MTR_ENA,min(abs(pwm),255));}
  else if(pwm<0){digitalWrite(MTR_IN1,LOW);digitalWrite(MTR_IN2,HIGH);analogWrite(MTR_ENA,min(abs(pwm),255));}
  else{digitalWrite(MTR_IN1,LOW);digitalWrite(MTR_IN2,LOW);analogWrite(MTR_ENA,0);}
}

void run_pid(float accel){
  float pos=(analogRead(POT_PIN)/1023.0f)*160.0f;
  float vel=(pos-lastPos)/DT; lastPos=pos;
  float sp=0.05f,e=fabs(accel)-sp;
  intg+=e*DT; intg=constrain(intg,-10,10);
  float d=(e-lastE)/DT; lastE=e;
  int out=(int)(80.0f*e+20.0f*intg+5.0f*d);
  drive_motor(-out*(accel>0?1:-1));
}

void run_alarm(float rms){
  if(rms>0.5f){tone(BUZZER,1500);analogWrite(LED,255);}
  else{noTone(BUZZER);analogWrite(LED,(int)(rms/0.5f*180));}
}

void setup(){Wire.begin();mpu.initialize();Serial.begin(115200);pinMode(MTR_IN1,OUTPUT);pinMode(MTR_IN2,OUTPUT);pinMode(MTR_ENA,OUTPUT);pinMode(BUZZER,OUTPUT);pinMode(LED,OUTPUT);}

void loop(){
  int16_t ax,ay,az,gx,gy,gz;
  mpu.getMotion6(&ax,&ay,&az,&gx,&gy,&gz);
  float a=(az/16384.0f)*9.81f;
  float rms=vibration_rms_window(a,vbuf,&vidx,BUF_N);
  run_pid(a);
  run_alarm(rms);
  Serial.print("rms=");Serial.println(rms);
  delay(20);
}
